const input = $input.first().json;
const body = input.body || input;

const service_id = String(body.service_id || 'google_calendar');
const action = String(body.action || 'check');
const error_message = body.error_message || null;
const metadata = body.metadata || {};

const SERVICE_ID_RE = /^[a-zA-Z0-9_-]{1,100}$/;
if (!SERVICE_ID_RE.test(service_id)) {
  throw new Error('Invalid service_id: must be alphanumeric/underscore/hyphen, max 100 chars');
}

const VALID_ACTIONS = ['check', 'record_success', 'record_failure'];
if (!VALID_ACTIONS.includes(action)) {
  throw new Error('Invalid action: ' + action);
}

const safe_error = error_message
  ? String(error_message).substring(0, 500)
  : null;

return [{ json: { service_id, action, error_message: safe_error, metadata } }];

const items = $input.all();
const service_id = $('Validate Input').first().json.service_id;

if (!items.length || !items[0].json || !items[0].json.service_id) {
  return [{ json: {
    service_id: service_id,
    state: 'closed',
    failure_count: 0,
    success_count: 0,
    failure_threshold: 5,
    success_threshold: 3,
    timeout_seconds: 300,
    opened_at: null,
    _is_default: true
  }}];
}

return [{ json: { ...items[0].json, _is_default: false } }];

const state = $input.first().json;
const isHalfOpen = state.state === 'half-open';

return [{ json: {
  allowed: true,
  circuit_state: isHalfOpen ? 'half-open' : 'closed',
  message: isHalfOpen
    ? 'Circuit in half-open state - test request allowed'
    : 'Service is healthy - requests allowed',
  failure_count: state.failure_count || 0,
  service_id: state.service_id
}}];

const state = $input.first().json;
const now = new Date();
const openedAt = state.opened_at ? new Date(state.opened_at) : null;
const timeoutSeconds = state.timeout_seconds || 300;

let shouldTryHalfOpen = false;
let timeUntilRetry = 0;

if (openedAt) {
  const elapsedSeconds = (now.getTime() - openedAt.getTime()) / 1000;
  if (elapsedSeconds >= timeoutSeconds) {
    shouldTryHalfOpen = true;
  } else {
    timeUntilRetry = Math.ceil(timeoutSeconds - elapsedSeconds);
  }
}

return [{ json: {
  ...state,
  should_try_half_open: shouldTryHalfOpen,
  time_until_retry_seconds: timeUntilRetry,
  elapsed_since_open: openedAt ? Math.floor((now.getTime() - openedAt.getTime()) / 1000) : null
}}];

const state = $input.first().json;

return [{ json: {
  allowed: true,
  circuit_state: 'half-open',
  message: 'Circuit transitioned to half-open - test request allowed',
  service_id: state.service_id,
  failure_count: state.failure_count || 0,
  opened_at: state.opened_at,
  time_until_retry_seconds: 0
}}];

const state = $input.first().json;

return [{ json: {
  allowed: false,
  circuit_state: 'open',
  message: 'Circuit breaker OPEN - service unavailable. Retry in ' + (state.time_until_retry_seconds || 'unknown') + ' seconds',
  service_id: state.service_id,
  retry_after_seconds: state.time_until_retry_seconds || 300,
  failure_count: state.failure_count || 0
}}];

let cbResult = null;

if ($('Return Allowed').isExecuted) {
  cbResult = $('Return Allowed').first().json;
} else if ($('Return Half-Open').isExecuted) {
  cbResult = $('Return Half-Open').first().json;
} else if ($('Return Blocked').isExecuted) {
  cbResult = $('Return Blocked').first().json;
}

if (!cbResult) {
  cbResult = { allowed: false, circuit_state: 'unknown', message: 'No circuit state resolved' };
}

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: cbResult,
  _meta: {
    source: 'CB_GCal_Circuit_Breaker',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id || 'unknown'
  }
}}];
